using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class TicketClassificationResult
{
    public required string PredictedCategory { get; set; }
    public required Dictionary<string, float> Probabilities { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelTrainer
{
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<TicketModelTrainer> _logger;

    public TicketModelTrainer(IConfiguration configuration, ILogger<TicketModelTrainer> logger)
    {
        _dataPath = configuration.GetValue<string>("ML:DataPath")
            ?? Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        _modelPath = configuration.GetValue<string>("ML:ModelPath")
            ?? Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        _logger = logger;
    }

    public string ModelPath => _modelPath;

    public void Train()
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(mlContext)
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model with data from {DataPath}...", _dataPath);
        var model = pipeline.Fit(split.TrainSet);

        Evaluate(mlContext, model, split.TestSet);

        mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", _modelPath);
    }

    private void Evaluate(MLContext mlContext, ITransformer model, IDataView testData)
    {
        var predictions = model.Transform(testData);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("MacroAccuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("MicroAccuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("LogLoss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("LogLossReduction: {LogLossReduction:F4}", metrics.LogLossReduction);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;

    public TicketsController(PredictionEnginePool<TicketData, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<TicketClassificationResult> Classify([FromBody] TicketRequest request)
    {
        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);
        var labels = new[] { "Billing", "General", "Technical" };

        var probabilities = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < labels.Length; i++)
            probabilities[labels[i]] = prediction.Score[i];

        return Ok(new TicketClassificationResult
        {
            PredictedCategory = prediction.Category,
            Probabilities = probabilities
        });
    }
}

