using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelTrainer
{
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<TicketModelTrainer> _logger;

    public TicketModelTrainer(IConfiguration configuration, ILogger<TicketModelTrainer> logger)
    {
        _dataPath = configuration.GetValue<string>("ML:DataPath")
            ?? Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        _modelPath = configuration.GetValue<string>("ML:ModelPath")
            ?? Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        _logger = logger;
    }

    public string ModelPath => _modelPath;

    /// <summary>
    /// Trains the model and returns the ordered category labels matching the Score column slots.
    /// </summary>
    public string[] Train()
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(mlContext)
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model with data from {DataPath}...", _dataPath);
        var model = pipeline.Fit(split.TrainSet);

        Evaluate(mlContext, model, split.TestSet);

        mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", _modelPath);

        // Extract ordered label names from the Score column metadata
        var scoreMeta = model.Transform(split.TrainSet).Schema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreMeta.GetSlotNames(ref slotNames);
        return slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }

