using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train the model before the host starts
var modelTrainer = new TicketModelTrainer(builder.Configuration,
    LoggerFactory.Create(b => b.AddConsole()).CreateLogger<TicketModelTrainer>());
var labels = modelTrainer.Train();

builder.Services.AddSingleton(new LabelMetadata { Labels = labels });
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelTrainer.ModelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

